package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithIgnoreEmptyLines() {
        CSVFormat format = CSVFormat.DEFAULT;
        // Call the focal method
        CSVFormat newFormat = format.withIgnoreEmptyLines();

        // It should return a new CSVFormat instance, not the same one
        assertNotSame(format, newFormat);

        // The new instance should have ignoreEmptyLines set to true
        assertTrue(newFormat.getIgnoreEmptyLines());

        // The original instance should remain unchanged (DEFAULT has ignoreEmptyLines = true)
        // Adjusted assertion to match actual DEFAULT value
        assertTrue(format.getIgnoreEmptyLines());

        // Also test that withIgnoreEmptyLines(true) returns an instance with ignoreEmptyLines true
        CSVFormat formatTrue = format.withIgnoreEmptyLines(true);
        assertTrue(formatTrue.getIgnoreEmptyLines());

        // Test that withIgnoreEmptyLines(false) returns an instance with ignoreEmptyLines false
        CSVFormat formatFalse = format.withIgnoreEmptyLines(false);
        assertFalse(formatFalse.getIgnoreEmptyLines());
    }
}
